export interface HairStyle {
  id: string;
  name: string;
  matchScore: number;
  image: string;
  description: string;
  maintenance: 'Low' | 'Medium' | 'High';
  bestFor: string[];
}

export type VibeType = 'bold' | 'classic' | 'natural' | 'fun';

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeGroomingStyle = async (imageData: string, mode: 'Human' | 'Pet', vibe: string) => {
  const prompt = `Analyze this ${mode} face for grooming styles. The user prefers a "${vibe}" vibe. Provide 3 specific hairstyle recommendations in JSON format. Each should include a name, match percentage, and brief description of why it fits.`;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: [
      {
        parts: [
          { inlineData: { mimeType: "image/jpeg", data: imageData.split(',')[1] } },
          { text: prompt }
        ]
      }
    ],
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          recommendations: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                matchScore: { type: Type.NUMBER },
                description: { type: Type.STRING },
                maintenance: { type: Type.STRING },
                bestFor: { type: Type.ARRAY, items: { type: Type.STRING } }
              },
              required: ["name", "matchScore", "description"]
            }
          }
        }
      }
    }
  });

  return JSON.parse(response.text || '{"recommendations": []}');
};

