import React, { useState, useRef, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { analyzeGroomingStyle } from '../services/geminiService';

interface ScanProps {
  vibe: string;
  onAnalysisComplete: (result: any, image: string) => void;
}

const ScanScreen: React.FC<ScanProps> = ({ vibe, onAnalysisComplete }) => {
  const navigate = useNavigate();
  const [mode, setMode] = useState<'Human' | 'Pet'>('Human');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [permissionError, setPermissionError] = useState<string | null>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    startCamera();
    return () => stopCamera();
  }, []);

  const startCamera = async () => {
    setPermissionError(null);
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { 
          facingMode: 'user', 
          width: { ideal: 1280 }, 
          height: { ideal: 720 } 
        }, 
        audio: false 
      });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
      }
    } catch (err: any) {
      console.error("Error accessing camera:", err);
      if (err.name === 'NotAllowedError' || err.name === 'PermissionDeniedError') {
        setPermissionError("Camera access denied. Please enable camera permissions in your browser settings to use the scanner.");
      } else {
        setPermissionError("Could not access camera. Please ensure no other app is using it.");
      }
    }
  };

  const stopCamera = () => {
    if (videoRef.current && videoRef.current.srcObject) {
      const stream = videoRef.current.srcObject as MediaStream;
      stream.getTracks().forEach(track => track.stop());
    }
  };

  const captureAndAnalyze = async () => {
    if (!videoRef.current || !canvasRef.current || isAnalyzing) return;

    // Check if video is actually ready
    if (videoRef.current.readyState < 2) {
      alert("Camera is still warming up. Please wait a moment.");
      return;
    }

    setIsAnalyzing(true);
    const canvas = canvasRef.current;
    const video = videoRef.current;

    // Use natural video dimensions to ensure high quality
    canvas.width = video.videoWidth || 1280;
    canvas.height = video.videoHeight || 720;
    const ctx = canvas.getContext('2d');

    if (ctx) {
      ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
      // High quality jpeg for better AI processing
      const imageData = canvas.toDataURL('image/jpeg', 0.9);

      try {
        const results = await analyzeGroomingStyle(imageData, mode, vibe);
        onAnalysisComplete(results, imageData);
        navigate('/results');
      } catch (error: any) {
        console.error("Analysis failed:", error);
        // Better error message for the user
        const msg = error.message?.includes("INVALID_ARGUMENT") 
          ? "The AI couldn't clearly see a face. Please ensure you're in a well-lit area and try again."
          : "Oops! Something went wrong with the analysis. Please try again.";
        alert(msg);
      } finally {
        setIsAnalyzing(false);
      }
    }
  };

  return (
    <div className="relative h-screen bg-background-dark flex flex-col overflow-hidden">
      <div className="flex items-center p-4 justify-between z-20">
        <button onClick={() => navigate('/quiz')} className="text-white size-12 flex items-center justify-start">
          <span className="material-symbols-outlined">close</span>
        </button>
        <h2 className="text-white text-lg font-bold">Face Analysis</h2>
        <div className="w-12"></div>
      </div>

      <div className="flex px-10 py-4 z-20">
        <div className="flex h-12 flex-1 items-center justify-center rounded-xl bg-white/5 backdrop-blur-sm p-1 border border-white/10">
          <button 
            onClick={() => setMode('Human')}
            className={`flex flex-1 items-center justify-center rounded-lg h-full transition-all gap-2 text-sm font-bold ${mode === 'Human' ? 'bg-primary text-black' : 'text-white/60'}`}
          >
            <span className="material-symbols-outlined text-lg">person</span> Human
          </button>
          <button 
            onClick={() => setMode('Pet')}
            className={`flex flex-1 items-center justify-center rounded-lg h-full transition-all gap-2 text-sm font-bold ${mode === 'Pet' ? 'bg-primary text-black' : 'text-white/60'}`}
          >
            <span className="material-symbols-outlined text-lg">pets</span> Pet
          </button>
        </div>
      </div>

      <div className="relative flex-1 bg-black">
        {permissionError ? (
          <div className="absolute inset-0 flex flex-col items-center justify-center p-8 text-center bg-background-dark">
            <span className="material-symbols-outlined text-red-500 text-6xl mb-4">no_photography</span>
            <p className="text-white font-medium mb-6">{permissionError}</p>
            <button 
              onClick={startCamera}
              className="bg-primary text-black font-bold py-3 px-8 rounded-xl"
            >
              Try Again
            </button>
          </div>
        ) : (
          <>
            <video 
              ref={videoRef} 
              autoPlay 
              playsInline 
              className="w-full h-full object-cover grayscale-[0.2]"
            />
            <canvas ref={canvasRef} className="hidden" />

            <div className="absolute inset-0 scan-overlay flex flex-col items-center justify-center">
