import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeGroomingStyle = async (imageData: string, mode: 'Human' | 'Pet', vibe: string) => {
  // Extract base64 part correctly
  const base64Data = imageData.split(',')[1];
  if (!base64Data) {
    throw new Error("Invalid image data provided to AI service.");
  }

  const prompt = `You are a professional ${mode === 'Human' ? 'hair stylist' : 'pet groomer'}. 
  Analyze the uploaded image of a ${mode}. 
  The user is looking for a style with a "${vibe}" vibe. 

  Provide 3 specific and creative grooming/hairstyle recommendations in JSON format.
  Focus on:
  1. Face shape and feature enhancement.
  2. How the "${vibe}" vibe translates to a look.
  3. Maintenance level.

  Return exactly this structure:
  {
    "recommendations": [
      {
        "name": "Style Name",
        "matchScore": 95,
        "description": "Why this works for them...",
        "maintenance": "Low/Medium/High",
        "bestFor": ["Feature 1", "Feature 2"]
      }
    ]
  }`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: [
        {
          parts: [
            { inlineData: { mimeType: "image/jpeg", data: base64Data } },
            { text: prompt }
          ]
        }
      ],
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            recommendations: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  name: { type: Type.STRING },
                  matchScore: { type: Type.NUMBER },
                  description: { type: Type.STRING },
                  maintenance: { type: Type.STRING },
                  bestFor: { type: Type.ARRAY, items: { type: Type.STRING } }
                },
                required: ["name", "matchScore", "description", "maintenance", "bestFor"]
              }
            }
          }
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("Empty response from Gemini API");

    return JSON.parse(text);
  } catch (err: any) {
    console.error("Gemini API Error Details:", err);
    throw err;
  }
};

import React, { useState, useRef, useEffect } from 'react';
