                className="text-white/60 font-medium py-2 px-8 text-sm"
              >
                Retry Camera
              </button>
            </div>
          </div>
        ) : (
          <>
            <video 
              ref={videoRef} 
              autoPlay 
              playsInline 
              className="w-full h-full object-cover grayscale-[0.2]"
            />
            <canvas ref={canvasRef} className="hidden" />

